tikzpicture[scale=0.55]
 % Grid
 (-5,-3) grid (5,5);
 % Axes
 (-5.5,0) – (5.5,0) node[right] {$x$};
 (0,-3.5) – (0,5.5) node[above] {$y$};
 % Directrix
 (-5,-2) – (5,-2);
 at (5.2,-2) {$y=-2$};
 % Parabola

 plot (, {0.125*});
 % Vertex
 ll[AtlasSage] (0,0) circle (4pt);
 at (0,0) {$(0,0)$};
 % Focus
 ll[AtlasWarm] (0,2) circle (4pt);
 at (0.2,2) {$(0,2)$};
 % Additional points
 ll[black] (4,2) circle (3pt);
 ll[black] (-4,2) circle (3pt);
